---
import type { HTMLAttributes } from "astro/types"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const variants = cva(
  "peer/menu-button group/menu-button flex w-full items-center gap-2 overflow-hidden rounded-md p-2 text-left text-sm ring-sidebar-ring outline-hidden transition-[width,height,padding] group-has-data-[sidebar=menu-action]/menu-item:pr-8 group-data-[collapsible=icon]:size-8! group-data-[collapsible=icon]:p-2! group-data-[collapsible=icon]:justify-center group-data-[collapsible=icon]:gap-0 group-data-[collapsible=icon]:[&>*:not(:first-child)]:hidden hover:bg-sidebar-accent hover:text-sidebar-accent-foreground focus-visible:ring-2 active:bg-sidebar-accent active:text-sidebar-accent-foreground disabled:pointer-events-none disabled:opacity-50 aria-disabled:pointer-events-none aria-disabled:opacity-50 data-open:hover:bg-sidebar-accent data-open:hover:text-sidebar-accent-foreground data-active:bg-sidebar-accent data-active:font-medium data-active:text-sidebar-accent-foreground [&_svg]:size-4 [&_svg]:shrink-0 [&>span:last-child]:truncate",
  {
    variants: {
      variant: {
        default: "hover:bg-sidebar-accent hover:text-sidebar-accent-foreground",
        outline:
          "bg-background shadow-[0_0_0_1px_hsl(var(--sidebar-border))] hover:bg-sidebar-accent hover:text-sidebar-accent-foreground hover:shadow-[0_0_0_1px_hsl(var(--sidebar-accent))]",
      },
      size: {
        default: "h-8 text-sm",
        sm: "h-7 text-xs",
        lg: "h-12 text-sm group-data-[collapsible=icon]:p-0!",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

type TooltipValue =
  | string
  | {
      content?: string
      children?: string
    }

type Props = VariantProps<typeof variants> &
  HTMLAttributes<"button"> &
  HTMLAttributes<"a"> &
  HTMLAttributes<"div"> &
  HTMLAttributes<"span"> & {
    as?: "a" | "button" | "div" | "span"
    href?: string
    isActive?: boolean
    active?: boolean
    tooltip?: TooltipValue
  }

const {
  as: explicitTag,
  class: className,
  variant = "default",
  size = "default",
  isActive,
  active = false,
  tooltip,
  "aria-label": ariaLabel,
  title,
  type,
  ...props
} = Astro.props as Props

const Tag = explicitTag || ("href" in Astro.props ? "a" : "button")
const resolvedActive = isActive ?? active
const tooltipText =
  typeof tooltip === "string"
    ? tooltip
    : tooltip?.content || tooltip?.children
---

<Tag
  data-slot="sidebar-menu-button"
  data-sidebar="menu-button"
  data-size={size}
  data-active={resolvedActive ? "true" : undefined}
  data-tooltip={tooltipText}
  aria-current={resolvedActive ? "page" : undefined}
  aria-label={typeof ariaLabel === "string" ? ariaLabel : tooltipText}
  title={typeof title === "string" ? title : undefined}
  type={Tag === "button" ? type || "button" : undefined}
  class={cn(variants({ variant, size }), className)}
  {...props}
>
  <slot />
</Tag>

