import type { HTMLAttributes } from "astro/types"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const variants = cva(
  "flex h-7 min-w-0 -translate-x-px items-center gap-2 overflow-hidden rounded-md px-2 text-sidebar-foreground ring-sidebar-ring outline-hidden group-data-[collapsible=icon]:hidden hover:bg-sidebar-accent hover:text-sidebar-accent-foreground focus-visible:ring-2 active:bg-sidebar-accent active:text-sidebar-accent-foreground disabled:pointer-events-none disabled:opacity-50 aria-disabled:pointer-events-none aria-disabled:opacity-50 data-[size=md]:text-sm data-[size=sm]:text-xs data-active:bg-sidebar-accent data-active:text-sidebar-accent-foreground [&>span:last-child]:truncate [&>svg]:size-4 [&>svg]:shrink-0 [&>svg]:text-sidebar-accent-foreground",
  {
    variants: {
      size: {
        sm: "text-xs",
        md: "text-sm",
      },
    },
    defaultVariants: {
      size: "md",
    },
  }
)

type Props = VariantProps<typeof variants> &
  HTMLAttributes<"button"> &
  HTMLAttributes<"a"> &
  HTMLAttributes<"span"> & {
    as?: "a" | "button" | "span"
    href?: string
    isActive?: boolean
    active?: boolean
  }

const {
  as: explicitTag,
  class: className,
  size = "md",
  isActive,
  active = false,
  type,
  ...props
} = Astro.props as Props

const Tag = explicitTag || ("href" in Astro.props ? "a" : "button")
const resolvedActive = isActive ?? active
---

<Tag
  data-slot="sidebar-menu-sub-button"
  data-sidebar="menu-sub-button"
  data-size={size}
  data-active={resolvedActive ? "true" : undefined}
  aria-current={resolvedActive ? "page" : undefined}
  type={Tag === "button" ? type || "button" : undefined}
  class={cn(variants({ size }), className)}
  {...props}
>
  <slot />
</Tag>
